const struct letter* const letters = (struct letter*) letterBytes;

const struct letterSet basicFont = {letters, 94};

bool getLetterPixel(struct letterSet letterSet, int letter, int row, int col) {
    letter -= '!';
    if (letter >= letterSet.letterMax || letter < 0) return 0;
    if (col >= 3 || col < 0) return 0;
    if (row >= 5 || row < 0) return 0;
    return letterSet.letters[letter].rows[row].cols[col];
}

int drawString(char* string, rect_t* rect, const struct letterSet letterSet, pixel_t color, pixel_t backgroundColor, int charWidth, int charHeight) {
    if (rect->width < charWidth || rect->height < charHeight) return 0;
    int symbolWidth = charWidth - 1;
    int symbolHeight = charHeight - 1;
    static uint8_t imageBuffer[sizeof(image_t) + sizeof(pixel_t) * 5 * 3];
    static image_t* image = (image_t*) imageBuffer;
    *image = (image_t) {
        0,
        absoluteSymbolWidth,
        absoluteSymbolHeight,
        "",
        false
    };
    int stringLength = strlen(string);
    int charsPrinted = 0;
    for (int i = 0; i < stringLength; i++) {
        charsPrinted = i + 1;
        char c = string[i];
        int baseX = charWidth * i;
        if (baseX + charWidth >= rect->width) {
            charsPrinted--;
            goto finish;
        }
        int baseY = (baseX / rect->width) * charHeight;
        if (baseY >= + rect->height) {
            charsPrinted--;
            goto finish;
        }
        baseX %= rect->width;
        baseX += rect->x;
        baseY += rect->y;
        for (int y = 0; y < absoluteSymbolHeight; y++) {
            for (int x = 0; x < absoluteSymbolWidth; x++) {
                bool draw = getLetterPixel(letterSet, c, y, x);
                pixel_t thisColor = color;
                if (!draw) thisColor = backgroundColor;
                thisColor.a = 255;
                image->pixels[y * absoluteSymbolWidth + x] = thisColor;
            }
        }
        drawImage(image, baseX, baseY, symbolWidth, symbolHeight);
    }
finish: {}
    int maxWidth = MIN(charsPrinted * charWidth, rect->width);
    int maxHeight;
    if (rect->width != 0) maxHeight = MAX(charHeight, (charsPrinted * charWidth / rect->width));
    else maxHeight = charHeight;
    rect->width = maxWidth;
    rect->height = maxHeight;
    return charsPrinted;
}
